using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    [DataRow("Doe", "John", "Doe, John", DisplayName = "Standard name")]
    [DataRow("Smith", "Jane", "Smith, Jane", DisplayName = "Another name")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
    public void FullName_WithLastAndFirst_ReturnsCommaSeparated(string lastName, string firstName, string expected)
    {
        // Arrange — use Student as concrete implementation of abstract Person
        var person = new Student
        {
            LastName = lastName,
            FirstMidName = firstName
        };

        // Act
        var result = person.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FullName_WithEmptyStrings_ReturnsCommaSpace()
    {
        var person = new Student { LastName = "", FirstMidName = "" };
        Assert.AreEqual(", ", person.FullName);
    }

    [TestMethod]
    public void ID_SetAndGet_RoundTrips()
    {
        var person = new Student { ID = 42 };
        Assert.AreEqual(42, person.ID);
    }

    [TestMethod]
    public void LastName_SetAndGet_RoundTrips()
    {
        var person = new Student { LastName = "TestLast" };
        Assert.AreEqual("TestLast", person.LastName);
    }

    [TestMethod]
    public void FirstMidName_SetAndGet_RoundTrips()
    {
        var person = new Student { FirstMidName = "TestFirst" };
        Assert.AreEqual("TestFirst", person.FirstMidName);
    }
}

