using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class StudentTests
{
    [TestMethod]
    public void EnrollmentDate_SetAndGet_RoundTrips()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void Enrollments_DefaultNull_IsNull()
    {
        var student = new Student();
        Assert.IsNull(student.Enrollments);
    }

    [TestMethod]
    public void Enrollments_SetToCollection_ReturnsCollection()
    {
        var enrollments = new List<Enrollment>
        {
            new Enrollment { EnrollmentID = 1, CourseID = 100, StudentID = 1 },
            new Enrollment { EnrollmentID = 2, CourseID = 200, StudentID = 1 }
        };
        var student = new Student { Enrollments = enrollments };

        Assert.AreEqual(2, student.Enrollments.Count);
    }

    [TestMethod]
    public void Student_InheritsFromPerson_HasFullName()
    {
        var student = new Student
        {
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };

        Assert.AreEqual("Alexander, Carson", student.FullName);
        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void Student_AllProperties_CanBeSet()
    {
        var date = new DateTime(2023, 1, 15);
        var student = new Student
        {
            ID = 5,
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = date,
            Enrollments = new List<Enrollment>()
        };

        Assert.AreEqual(5, student.ID);
        Assert.AreEqual("Test", student.LastName);
        Assert.AreEqual("Student", student.FirstMidName);
        Assert.AreEqual(date, student.EnrollmentDate);
        Assert.AreEqual(0, student.Enrollments.Count);
    }
}

