using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_WithItems_ContainsAllItems()
    {
        var items = new List<string> { "A", "B", "C" };
        var list = new PaginatedList<string>(items, 10, 1, 3);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("A", list[0]);
        Assert.AreEqual("B", list[1]);
        Assert.AreEqual("C", list[2]);
    }

    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        var list = new PaginatedList<int>(new List<int>(), 0, 3, 10);
        Assert.AreEqual(3, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items / 5 per page = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items / 5 per page = 3 pages (ceiling)")]
    [DataRow(0, 5, 0, DisplayName = "0 items = 0 pages")]
    [DataRow(1, 10, 1, DisplayName = "1 item / 10 per page = 1 page")]
    [DataRow(100, 10, 10, DisplayName = "100 items / 10 per page = 10 pages")]
    public void Constructor_CalculatesTotalPages(int count, int pageSize, int expectedTotalPages)
    {
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotOnLastPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 5, 1, 10);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstPageItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsSecondPageItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
        Assert.AreEqual(3, result.PageIndex);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<string>().AsQueryable();
        var result = PaginatedList<string>.Create(source, 1, 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SingleItem_SinglePage()
    {
        var source = new[] { "only" }.AsQueryable();
        var result = PaginatedList<string>.Create(source, 1, 10);

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("only", result[0]);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_ExactlyOnePageFull_NoNextPage()
    {
        var source = Enumerable.Range(1, 10).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasNextPage);
        Assert.IsFalse(result.HasPreviousPage);
    }
}

