using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue after each test for isolation
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        var result = _sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("Student", result.EntityType);
        Assert.AreEqual("1", result.EntityId);
        Assert.AreEqual("CREATE", result.Operation);
        Assert.AreEqual("admin", result.CreatedBy);
        Assert.IsFalse(result.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_EnqueuesNotification()
    {
        _sut.SendNotification("Course", "1050", EntityOperation.UPDATE, "System");

        var result = _sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("Course", result.EntityType);
        Assert.AreEqual("1050", result.EntityId);
        Assert.AreEqual("UPDATE", result.Operation);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Department", "5", EntityOperation.DELETE);

        var result = _sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("System", result.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_CREATE_GeneratesCorrectMessage()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.AreEqual("New Student 'John Doe' has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_UPDATE_GeneratesCorrectMessage()
    {
        _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        Assert.AreEqual("Course 'Chemistry' has been updated", result.Message);
    }

    [TestMethod]
    public void SendNotification_DELETE_GeneratesCorrectMessage()
    {
        _sut.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        var result = _sut.ReceiveNotification();

        Assert.AreEqual("Department 'Engineering' has been deleted", result.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.AreEqual("New Student (ID: 42) has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_WithNullDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Course", "100", null, EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        Assert.AreEqual("Course (ID: 100) has been updated", result.Message);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Instructor", "5", "", EntityOperation.DELETE);

        var result = _sut.ReceiveNotification();

        Assert.AreEqual("Instructor (ID: 5) has been deleted", result.Message);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var result = _sut.ReceiveNotification();

        Assert.IsTrue(result.CreatedAt >= before && result.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.IsFalse(result.IsRead);
    }

    [TestMethod]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_FIFO_ReturnsInOrder()
    {
        _sut.SendNotification("First", "1", EntityOperation.CREATE);
        _sut.SendNotification("Second", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Third", "3", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.AreEqual("First", first.EntityType);
        Assert.AreEqual("Second", second.EntityType);
        Assert.AreEqual("Third", third.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_RemovesFromQueue()
    {
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op in the in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
        // If we get here without exception, the test passes
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        service.Dispose();
        // If we get here without exception, the test passes
    }

    [TestMethod]
    public void SendNotification_MultipleNotifications_AllRetrievable()
    {
        for (int i = 0; i < 5; i++)
        {
            _sut.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
        }

        int count = 0;
        while (_sut.ReceiveNotification() != null)
        {
            count++;
        }

        Assert.AreEqual(5, count);
    }
}

