using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateSeededContext();
        _controller = new StudentsController(_context);
        // Set up controller context for TempData
        var httpContext = new DefaultHttpContext();
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = httpContext
        };
        _controller.TempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_NoParams_ReturnsViewResult()
    {
        var result = _controller.Index(null, null, null, null);
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_NoParams_ReturnsAllStudents()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count); // 3 seeded students
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDesc_OrdersByLastNameDescending()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual("Anand", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual("Alexander", model[0].LastName); // 2010
        Assert.AreEqual("Alonso", model[1].LastName);    // 2012
        Assert.AreEqual("Anand", model[2].LastName);     // 2013
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual("Anand", model[0].LastName);     // 2013
        Assert.AreEqual("Alonso", model[1].LastName);    // 2012
        Assert.AreEqual("Alexander", model[2].LastName); // 2010
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Carson", model[0].FirstMidName);
    }

    [TestMethod]
    public void Index_SearchNoMatch_ReturnsEmpty()
    {
        var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Index_NewSearch_ResetsToPage1()
    {
        var result = _controller.Index(null, null, "Al", 5) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearch_UsesCurrentFilter()
    {
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParms()
    {
        _controller.Index(null, null, null, null);

        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithNameDescSort_SetsViewBagNameSortParmToEmpty()
    {
        _controller.Index("name_desc", null, null, null);

        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_WithDateSort_SetsViewBagDateSortParmToDateDesc()
    {
        _controller.Index("Date", null, null, null);

        Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
    }

    // Details tests
    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.Details(studentId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(studentId, model.ID);
    }

    [TestMethod]
    public void Details_ValidId_IncludesEnrollments()
    {
        var student = _context.Students.First(s => s.LastName == "Alexander");

        var result = _controller.Details(student.ID) as ViewResult;
        var model = result.Model as Student;

        Assert.IsNotNull(model.Enrollments);
        Assert.IsTrue(model.Enrollments.Count > 0);
    }

    // Create GET tests
    [TestMethod]
    public void CreateGet_ReturnsViewWithStudent()
    {
        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
    }

    [TestMethod]
    public void CreateGet_SetsDefaultEnrollmentDate()
    {
        var result = _controller.Create() as ViewResult;
        var model = result.Model as Student;

        Assert.AreEqual(System.DateTime.Today, model.EnrollmentDate);
    }

    // Create POST tests
    [TestMethod]
    public void CreatePost_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new System.DateTime(2024, 1, 15)
        };

        var result = _controller.Create(student);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void CreatePost_ValidStudent_AddsToDatabase()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new System.DateTime(2024, 1, 15)
        };

        _controller.Create(student);

        var saved = _context.Students.FirstOrDefault(s => s.LastName == "NewStudent");
        Assert.IsNotNull(saved);
        Assert.AreEqual("Test", saved.FirstMidName);
    }

    [TestMethod]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student { EnrollmentDate = new System.DateTime(2024, 1, 15) };

        var result = _controller.Create(student);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void CreatePost_MinValueEnrollmentDate_AddsModelError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Test",
            EnrollmentDate = System.DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void CreatePost_DateBeforeSqlMin_AddsModelError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Test",
            EnrollmentDate = new System.DateTime(1752, 12, 31)
        };

        _controller.Create(student);

        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // Edit GET tests
    [TestMethod]
    public void EditGet_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void EditGet_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(99999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void EditGet_ValidId_ReturnsViewWithStudent()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.Edit(studentId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.AreEqual(studentId, model.ID);
    }

    // Edit POST tests
    [TestMethod]
    public void EditPost_ValidStudent_RedirectsToIndex()
    {
        var student = _context.Students.First();
        // Detach to avoid tracking issues
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var editedStudent = new Student
        {
            ID = student.ID,
            LastName = "Updated",
            FirstMidName = student.FirstMidName,
            EnrollmentDate = student.EnrollmentDate
        };

        var result = _controller.Edit(editedStudent);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void EditPost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            ID = 1,
            EnrollmentDate = new System.DateTime(2024, 1, 15)
        };

        var result = _controller.Edit(student);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void EditPost_MinValueEnrollmentDate_AddsModelError()
    {
        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Test",
            EnrollmentDate = System.DateTime.MinValue
        };

        _controller.Edit(student);

        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // Delete GET tests
    [TestMethod]
    public void DeleteGet_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void DeleteGet_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(99999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void DeleteGet_ValidId_ReturnsViewWithStudent()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.Delete(studentId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.AreEqual(studentId, model.ID);
    }

    // Delete POST tests
    [TestMethod]
    public void DeleteConfirmed_ValidId_RedirectsToIndex()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.DeleteConfirmed(studentId);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesFromDatabase()
    {
        var student = _context.Students.First();
        var studentId = student.ID;
        var initialCount = _context.Students.Count();

        _controller.DeleteConfirmed(studentId);

        Assert.AreEqual(initialCount - 1, _context.Students.Count());
        Assert.IsNull(_context.Students.Find(studentId));
    }
}

