using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context;
    private DepartmentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateSeededContext();
        _controller = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    // Index tests
    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsAllDepartments()
    {
        var result = _controller.Index() as ViewResult;
        var model = result.Model as List<Department>;

        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // 2 seeded departments
    }

    [TestMethod]
    public void Index_IncludesAdministrator()
    {
        var result = _controller.Index() as ViewResult;
        var model = result.Model as List<Department>;

        // Departments should have their Administrator loaded
        Assert.IsTrue(model.All(d => d.Administrator != null));
    }

    // Details tests
    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(99999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.Details(deptId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(deptId, model.DepartmentID);
    }

    // Create GET tests
    [TestMethod]
    public void CreateGet_ReturnsViewResult()
    {
        var result = _controller.Create();
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void CreateGet_SetsViewBagInstructorID()
    {
        _controller.Create();
        Assert.IsNotNull(_controller.ViewBag.InstructorID);
    }

    // Create POST tests
    [TestMethod]
    public void CreatePost_ValidDepartment_RedirectsToIndex()
    {
        var dept = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = new System.DateTime(2024, 1, 1),
            InstructorID = _context.Instructors.First().ID
        };

        var result = _controller.Create(dept);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void CreatePost_ValidDepartment_AddsToDatabase()
    {
        var instructorId = _context.Instructors.First().ID;
        var dept = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = new System.DateTime(2024, 1, 1),
            InstructorID = instructorId
        };

        _controller.Create(dept);

        var saved = _context.Departments.FirstOrDefault(d => d.Name == "Physics");
        Assert.IsNotNull(saved);
        Assert.AreEqual(200000m, saved.Budget);
    }

    [TestMethod]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department();

        var result = _controller.Create(dept);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void CreatePost_InvalidModelState_SetsViewBagInstructorID()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { InstructorID = 1 };

        _controller.Create(dept);

        Assert.IsNotNull(_controller.ViewBag.InstructorID);
    }

    // Edit GET tests
    [TestMethod]
    public void EditGet_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void EditGet_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(99999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void EditGet_ValidId_ReturnsViewWithDepartment()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.Edit(deptId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual(deptId, model.DepartmentID);
    }

    [TestMethod]
    public void EditGet_ValidId_SetsViewBagInstructorID()
    {
        var deptId = _context.Departments.First().DepartmentID;

        _controller.Edit(deptId);

        Assert.IsNotNull(_controller.ViewBag.InstructorID);
    }

    // Edit POST tests
    [TestMethod]
    public void EditPost_ValidDepartment_RedirectsToIndex()
    {
        var dept = _context.Departments.First();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var editedDept = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated Name",
            Budget = dept.Budget,
            StartDate = dept.StartDate,
            InstructorID = dept.InstructorID
        };

        var result = _controller.Edit(editedDept);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void EditPost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { DepartmentID = 1 };

        var result = _controller.Edit(dept);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // Delete GET tests
    [TestMethod]
    public void DeleteGet_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void DeleteGet_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(99999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void DeleteGet_ValidId_ReturnsViewWithDepartment()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.Delete(deptId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual(deptId, model.DepartmentID);
    }

    // Delete POST tests
    [TestMethod]
    public void DeleteConfirmed_ValidId_RedirectsToIndex()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.DeleteConfirmed(deptId);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesFromDatabase()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var initialCount = _context.Departments.Count();

        _controller.DeleteConfirmed(deptId);

        Assert.AreEqual(initialCount - 1, _context.Departments.Count());
        Assert.IsNull(_context.Departments.Find(deptId));
    }
}

