using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateSeededContext();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    // Index tests
    [TestMethod]
    public void Index_NoParams_ReturnsViewResult()
    {
        var result = _controller.Index(null, null);
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_NoParams_ReturnsAllInstructors()
    {
        var result = _controller.Index(null, null) as ViewResult;
        var model = result.Model as InstructorIndexData;

        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count()); // 2 seeded instructors
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsCourses()
    {
        var instructorId = _context.Instructors.First().ID;

        var result = _controller.Index(instructorId, null) as ViewResult;
        var model = result.Model as InstructorIndexData;

        Assert.IsNotNull(model.Courses);
        Assert.IsTrue(model.Courses.Any());
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsViewBagInstructorID()
    {
        var instructorId = _context.Instructors.First().ID;

        _controller.Index(instructorId, null);

        Assert.AreEqual(instructorId, _controller.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Index_InstructorsOrderedByLastName()
    {
        var result = _controller.Index(null, null) as ViewResult;
        var model = result.Model as InstructorIndexData;
        var instructors = model.Instructors.ToList();

        Assert.AreEqual("Abercrombie", instructors[0].LastName);
        Assert.AreEqual("Fakhouri", instructors[1].LastName);
    }

    // Details tests
    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(99999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        var instructorId = _context.Instructors.First().ID;

        var result = _controller.Details(instructorId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructorId, model.ID);
    }

    // Create GET tests
    [TestMethod]
    public void CreateGet_ReturnsViewResult()
    {
        var result = _controller.Create();
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void CreateGet_ReturnsInstructorWithEmptyCourseAssignments()
    {
        var result = _controller.Create() as ViewResult;
        var model = result.Model as Instructor;

        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
        Assert.AreEqual(0, model.CourseAssignments.Count);
    }

    [TestMethod]
    public void CreateGet_SetsViewBagCourses()
    {
        _controller.Create();
        Assert.IsNotNull(_controller.ViewBag.Courses);
    }

    // Create POST tests
    [TestMethod]
    public void CreatePost_ValidInstructor_NoSelectedCourses_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2024, 1, 1)
        };

        var result = _controller.Create(instructor, null);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void CreatePost_ValidInstructor_AddsToDatabase()
    {
        var instructor = new Instructor
        {
            LastName = "Created",
            FirstMidName = "New",
            HireDate = new DateTime(2024, 6, 1)
        };

        _controller.Create(instructor, null);

        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Created");
        Assert.IsNotNull(saved);
        Assert.AreEqual("New", saved.FirstMidName);
    }

    [TestMethod]
    public void CreatePost_WithSelectedCourses_CreatesCourseAssignments()
    {
        var courseIds = _context.Courses.Select(c => c.CourseID.ToString()).ToArray();
        var instructor = new Instructor
        {
            LastName = "WithCourses",
            FirstMidName = "Test",
            HireDate = new DateTime(2024, 1, 1)
        };

        _controller.Create(instructor, courseIds);

        var saved = _context.Instructors.First(i => i.LastName == "WithCourses");
        var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
        Assert.AreEqual(courseIds.Length, assignments.Count);
    }

    [TestMethod]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            HireDate = new DateTime(2024, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // Delete GET tests
    [TestMethod]
    public void DeleteGet_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void DeleteGet_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(99999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void DeleteGet_ValidId_ReturnsViewWithInstructor()
    {
        var instructorId = _context.Instructors.First().ID;

        var result = _controller.Delete(instructorId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.AreEqual(instructorId, model.ID);
    }

    // Delete POST tests
    [TestMethod]
    public void DeleteConfirmed_ValidId_RedirectsToIndex()
    {
        var instructorId = _context.Instructors.First().ID;

        var result = _controller.DeleteConfirmed(instructorId);

        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesFromDatabase()
    {
        var instructorId = _context.Instructors.First().ID;
        var initialCount = _context.Instructors.Count();

        _controller.DeleteConfirmed(instructorId);

        Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorIsDeptAdmin_ClearsDepartmentAdmin()
    {
        // Get an instructor who is a department administrator
        var dept = _context.Departments.First();
        var instructorId = dept.InstructorID.Value;

        _controller.DeleteConfirmed(instructorId);

        // Re-read the department
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.IsNull(updatedDept.InstructorID);
    }
}

