using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;
    private NotificationService _notificationService;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateSeededContext();
        _controller = new NotificationsController(_context);
        _notificationService = new NotificationService();

        // Drain the static queue for test isolation
        while (_notificationService.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue after test
        while (_notificationService.ReceiveNotification() != null) { }
        _controller.Dispose();
        _context.Dispose();
        _notificationService.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithZeroCount()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);

        var value = result.Value;
        Assert.IsNotNull(value);

        // Use reflection to access anonymous type properties
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(successProp);
        Assert.IsNotNull(countProp);
        Assert.AreEqual(true, successProp.GetValue(value));
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Enqueue some notifications
        _notificationService.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
        _notificationService.SendNotification("Course", "100", "Math", EntityOperation.UPDATE, "admin");

        var result = _controller.GetNotifications();

        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(true, successProp.GetValue(value));
        Assert.AreEqual(2, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Enqueue more than 10 notifications
        for (int i = 0; i < 15; i++)
        {
            _notificationService.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();

        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_RemovesFromQueue()
    {
        _notificationService.SendNotification("Student", "1", EntityOperation.CREATE);

        // First call consumes the notification
        _controller.GetNotifications();

        // Second call should have no notifications
        var result = _controller.GetNotifications();

        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsJsonResult()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(1);

        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        // MarkAsRead is a no-op in the in-memory implementation, always succeeds
        var result1 = _controller.MarkAsRead(0);
        var result2 = _controller.MarkAsRead(999);
        var result3 = _controller.MarkAsRead(-1);

        var value1 = result1.Value;
        var value2 = result2.Value;
        var value3 = result3.Value;

        Assert.AreEqual(true, value1.GetType().GetProperty("success").GetValue(value1));
        Assert.AreEqual(true, value2.GetType().GetProperty("success").GetValue(value2));
        Assert.AreEqual(true, value3.GetType().GetProperty("success").GetValue(value3));
    }
}

