using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        var context = TestHelper.CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.Students.Count());
        context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        var context = TestHelper.CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(5, context.Instructors.Count());
        context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        var context = TestHelper.CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(4, context.Departments.Count());
        context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        var context = TestHelper.CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(7, context.Courses.Count());
        context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        var context = TestHelper.CreateContext();

        DbInitializer.Initialize(context);

        Assert.IsTrue(context.Enrollments.Count() > 0);
        context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        var context = TestHelper.CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(3, context.OfficeAssignments.Count());
        context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        var context = TestHelper.CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.CourseAssignments.Count());
        context.Dispose();
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicateData()
    {
        var context = TestHelper.CreateContext();

        // Initialize twice
        DbInitializer.Initialize(context);
        DbInitializer.Initialize(context);

        // Should still have the same number of students
        Assert.AreEqual(8, context.Students.Count());
